package com.evolua.content.infrastructure.security; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.stereotype.Component; @Component public class CurrentUserProvider { public AuthenticatedUser getCurrentUser() { Object principal = SecurityContextHolder.getContext().getAuthentication().getPrincipal(); if (principal instanceof AuthenticatedUser user) { return user; } throw new IllegalArgumentException("Authenticated user not found"); } }
